import sys
import itertools

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    H = int(data[1])
    W = int(data[2])

    tiles = []
    idx = 3
    for _ in range(N):
        A = int(data[idx])
        B = int(data[idx + 1])
        tiles.append((A, B))
        idx += 2

    total_area = H * W
    tile_areas = [a * b for a, b in tiles]
    total_tile_area = sum(tile_areas)

    if total_tile_area < total_area:
        print("No")
        return

    grid = [[False for _ in range(W)] for _ in range(H)]

    def can_place(x, y, a, b):
        if x + a > H or y + b > W:
            return False
        for i in range(x, x + a):
            for j in range(y, y + b):
                if grid[i][j]:
                    return False
        return True

    def place(x, y, a, b):
        for i in range(x, x + a):
            for j in range(y, y + b):
                grid[i][j] = True

    def unplace(x, y, a, b):
        for i in range(x, x + a):
            for j in range(y, y + b):
                grid[i][j] = False

    def backtrack(tile_idx, placed_area):
        if placed_area == total_area:
            return True

        if tile_idx == N:
            return False

        a, b = tiles[tile_idx]
        for rot in [0, 1]:
            if rot == 0:
                tile_a, tile_b = a, b
            else:
                tile_a, tile_b = b, a

            for x in range(H):
                for y in range(W):
                    if not grid[x][y]:
                        if can_place(x, y, tile_a, tile_b):
                            place(x, y, tile_a, tile_b)
                            if backtrack(tile_idx + 1, placed_area + tile_a * tile_b):
                                return True
                            unplace(x, y, tile_a, tile_b)
        return backtrack(tile_idx + 1, placed_area)

    if backtrack(0, 0):
        print("Yes")
    else:
        print("No")

if __name__ == "__main__":
    main()
